sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

    // Show info message when location is selected
    var message = "Make sure you select the correct location for your newspaper distribution.";

    // Display info message on the form
    g_form.addInfoMessage(message);

    // Optional: You can also log to console for debugging
    console.log('Location changed from: ' + oldValue + ' to: ' + newValue);
}
